@classmethod
def setup_dynamic_args(cls, args: dict[str, str]):
    """Set up args for easy access in renderer.

    Args:
        args: a dict of args
    """
    # Skip dynamic args that have already been registered by a previous route.
    args = {
        k: v
        for k, v in args.items()
        if not (
            (computed_var := cls.computed_vars.get(k)) is not None
            and isinstance(computed_var, DynamicRouteVar)
        )
    }
    if not args:
        return

    cls._check_overwritten_dynamic_args(list(args.keys()))

    def argsingle_factory(param: str):
        def inner_func(self: BaseState) -> str:
            return self.router._page.params.get(param, "")

        inner_func.__name__ = param

        return inner_func

    def arglist_factory(param: str):
        def inner_func(self: BaseState) -> list[str]:
            return self.router._page.params.get(param, [])

        inner_func.__name__ = param

        return inner_func

    dynamic_vars = {}
